static ccallback_signature_t quadpack_call_legacy_signatures[] = {
    {"double (double)", CB_1D},
    {"double (int, double)", CB_ND}, /* sic -- for backward compatibility only */
#if NPY_SIZEOF_SHORT == NPY_SIZEOF_INT
